2337→{
2338→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
2339→    // 4x2 tiled vd4dots GEMM: 4 output channels x 2 pixels per tile, LMUL=M2
2340→    // Halves pixel data reloads compared to v2 (2x2 tile, LMUL=M4)
2341→    (void)in_offset;
2342→
2343→    /* set up the second output pointers */
2344→    int8_t *out_0 = out;
2345→    int8_t *out_1 = out_0 + out_tensor_ch;
2346→    const int8_t *ptr_a0 = input_a;
2347→    long vl;
2348→
2349→    long maxvl_per_loop;
2350→    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2351→
2352→    // Register allocation (LMUL=M2):
2353→    // Accumulators: v0(ch0*pix0), v2(ch0*pix1), v4(ch1*pix0), v6(ch1*pix1),
2354→    //               v8(ch2*pix0), v10(ch2*pix1), v12(ch3*pix0), v14(ch3*pix1)
2355→    // Load buffers: v16(pix0), v18(pix1), v20(wt0), v22(wt1), v24(wt2), v26(wt3)
2356→    // Scratch: v28-v31
2357→
2358→    for (long cur_row = 0; (cur_row + 4) <= out_tensor_ch; cur_row += 4)
2359→    {
2360→        /* setup pointers for B (im2col columns / pixels) */
2361→        const int8_t *ptr_b0 = input_b;
2362→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
2363→
2364→        /* setup pointers for A (weight rows / channels) */
2365→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
2366→        const int8_t *ptr_a2 = ptr_a1 + num_col_a;
2367→        const int8_t *ptr_a3 = ptr_a2 + num_col_a;
2368→
2369→        //init the 8 accumulators
2370→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2371→        NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
2372→        NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
2373→        NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0x0);
2374→        NDS_VEC_VAND_VI(NDS_VEC_V6, NDS_VEC_V6, 0x0);
2375→        NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
2376→        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
2377→        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
2378→        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
2379→
2380→        long col_count = num_col_a;
2381→        while(col_count >= maxvl_per_loop)
2382→        {
2383→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2384→            // Load 2 pixel columns (reused across all 4 weight rows)
2385→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
2386→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
2387→            // Load 4 weight rows
2388→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
2389→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
2390→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
2391→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
2392→            ptr_a0 += vl;
2393→            ptr_a1 += vl;
2394→            ptr_a2 += vl;
2395→            ptr_a3 += vl;
2396→            ptr_b0 += vl;
2397→            ptr_b1 += vl;
2398→            col_count -= vl;
2399→
2400→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2401→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);  //ch0*pix0
2402→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);  //ch0*pix1
2403→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);  //ch1*pix0
2404→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);  //ch1*pix1
2405→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);  //ch2*pix0
2406→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);  //ch2*pix1
2407→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);  //ch3*pix0
2408→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);  //ch3*pix1
2409→        }
2410→
2411→        //extra process for the case of elements to be dot producted is not a mutiple of 4
2412→        if(col_count > 0)
2413→        {
2414→            //clean pixel buffers to avoid junk in tail affecting vd4dots
2415→            long tmp_avl;
2416→            tmp_avl = col_count + 3;
2417→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2418→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
2419→            NDS_VEC_VAND_VI(NDS_VEC_V18, NDS_VEC_V18, 0);
2420→
2421→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
2422→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_b0);
2423→            NDS_VEC_VLE8_V(NDS_VEC_V18, ptr_b1);
2424→            NDS_VEC_VLE8_V(NDS_VEC_V20, ptr_a0);
2425→            NDS_VEC_VLE8_V(NDS_VEC_V22, ptr_a1);
2426→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_a2);
2427→            NDS_VEC_VLE8_V(NDS_VEC_V26, ptr_a3);
2428→            ptr_a0 += vl;
2429→            ptr_a1 += vl;
2430→            ptr_a2 += vl;
2431→            ptr_a3 += vl;
2432→
2433→            vl = (vl + 3) >> 2;
2434→            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2435→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V0,  NDS_VEC_V20, NDS_VEC_V16);
2436→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V2,  NDS_VEC_V20, NDS_VEC_V18);
2437→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4,  NDS_VEC_V22, NDS_VEC_V16);
2438→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V6,  NDS_VEC_V22, NDS_VEC_V18);
2439→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8,  NDS_VEC_V24, NDS_VEC_V16);
2440→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V10, NDS_VEC_V24, NDS_VEC_V18);
2441→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V12, NDS_VEC_V26, NDS_VEC_V16);
2442→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V14, NDS_VEC_V26, NDS_VEC_V18);
2443→        }
2444→
2445→        // === Reduction epilogue: 8 vredsum → pack to VL=4 → requantize ===
2446→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2447→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
2448→        NDS_VEC_VSETVLI(vl, num_col_a, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M2);
2449→
2450→        // Reduce 8 accumulators to scalars in element [0]
2451→        NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0 → v16[0]
2452→        NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0 → v17[0]
2453→        NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0 → v18[0]
2454→        NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0 → v19[0]
2455→        NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix1 → v20[0]
2456→        NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix1 → v21[0]
2457→        NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix1 → v22[0]
2458→        NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix1 → v23[0]
2459→
2460→        // Pack 4 scalars into VL=4 vectors via vslideup
2461→        // pix0: v16 = [ch0, ch1, ch2, ch3]
2462→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2463→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
2464→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
2465→        NDS_VEC_VSETVLI(vl, 3, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2466→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
2467→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
2468→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2469→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);
2470→        NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);
2471→
2472→        // v16 = pix0 [ch0,ch1,ch2,ch3], v20 = pix1 [ch0,ch1,ch2,ch3]
2473→
2474→        //add extra contribution back
2475→        NDS_VEC_VLE32_V(NDS_VEC_V24, contri_buf);
2476→        contri_buf += vl;
2477→        NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V24);
2478→        NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V24);
