2481→        NDS_VEC_VLE32_V(NDS_VEC_V2, out_shift);
2482→        NDS_VEC_VLE32_V(NDS_VEC_V3, out_scale);
2483→        NDS_VEC_VRSUB_VX(NDS_VEC_V2, NDS_VEC_V2, 30);
