2485→        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V3);
2486→        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V20, NDS_VEC_V3);
2487→        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
2488→        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
2489→        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
2490→        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
2491→
2492→        // Add offset
2493→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
2494→        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
