2496→        // Clamp the result
2497→        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
2498→        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
2499→        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
2500→        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
2501→
2502→        //narrowing and store the results
2503→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
2504→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2505→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2506→        NDS_VEC_VSETVLI(vl, 4, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
2507→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2508→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2509→        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
2510→        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
2511→        out_0 += 4;
2512→        out_1 += 4;
2513→        out_scale += 4;
2514→        out_shift += 4;
2515→
2516→        ptr_a0 += 3 * (long)num_col_a;  // skip past channels 1,2,3
2517→    }
2518→
2519→    // === Handle remaining 2 channels (if out_tensor_ch % 4 >= 2) ===
2520→    if ((out_tensor_ch & 0x3) >= 2)
2521→    {
2522→        const int8_t *ptr_b0 = input_b;
2523→        const int8_t *ptr_b1 = ptr_b0 + num_col_a;
2524→        const int8_t *ptr_a1 = ptr_a0 + num_col_a;
