2551→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V28);
2552→            NDS_VEC_VD4DOTS_VV(NDS_VEC_V8, NDS_VEC_V20, NDS_VEC_V24);
