2556→        if(col_count > 0)
2557→        {
2558→            long tmp_avl = col_count + 3;
2559→            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
