2561→            NDS_VEC_VAND_VI(NDS_VEC_V28, NDS_VEC_V28, 0);
2562→
2563→            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M4);
2564→            NDS_VEC_VLE8_V(NDS_VEC_V16, ptr_a0);
2565→            NDS_VEC_VLE8_V(NDS_VEC_V24, ptr_b0);
2566→            NDS_VEC_VLE8_V(NDS_VEC_V28, ptr_b1);
