2579→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
2580→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);
