2591→        NDS_VEC_VLE32_V(NDS_VEC_V4, contri_buf);
2592→        contri_buf += vl;
2593→        NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V4);
