2600→        NDS_VEC_VWMUL_VV(NDS_VEC_V4, NDS_VEC_V0, NDS_VEC_V3);
2601→        NDS_VEC_VWMUL_VV(NDS_VEC_V6, NDS_VEC_V1, NDS_VEC_V3);
2602→        NDS_VEC_VNSRA_WV(NDS_VEC_V4, NDS_VEC_V4, NDS_VEC_V2);
2603→        NDS_VEC_VNSRA_WV(NDS_VEC_V6, NDS_VEC_V6, NDS_VEC_V2);
2604→        NDS_VEC_VSSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 1);
2605→        NDS_VEC_VSSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 1);
2606→
2607→        NDS_VEC_VADD_VX(NDS_VEC_V4, NDS_VEC_V4, out_offset);
2608→        NDS_VEC_VADD_VX(NDS_VEC_V6, NDS_VEC_V6, out_offset);
2609→
2610→        NDS_VEC_VMAX_VX(NDS_VEC_V4, NDS_VEC_V4, act_min);
2611→        NDS_VEC_VMIN_VX(NDS_VEC_V4, NDS_VEC_V4, act_max);
2612→        NDS_VEC_VMAX_VX(NDS_VEC_V6, NDS_VEC_V6, act_min);
2613→        NDS_VEC_VMIN_VX(NDS_VEC_V6, NDS_VEC_V6, act_max);
2614→
2615→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M1);
2616→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2617→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2618→        NDS_VEC_VSETVLI(vl, 2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
2619→        NDS_VEC_VNSRA_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
2620→        NDS_VEC_VNSRA_VI(NDS_VEC_V6, NDS_VEC_V6, 0);
2621→        NDS_VEC_VSE8_V(NDS_VEC_V4, out_0);
2622→        NDS_VEC_VSE8_V(NDS_VEC_V6, out_1);
2623→        out_0 += 2;
2624→        out_1 += 2;

