        if (bias)
        {
            vint32m1_t vbias = __riscv_vle32_v_i32m1(bias, vl);
            bias += vl;
            vch_0_out_0 = __riscv_vadd(vch_0_out_0, vbias, vl);
            vch_0_out_1 = __riscv_vadd(vch_0_out_1, vbias, vl);
        }

        //===== Quantize down =====
        vint32m1_t vout_shift = __riscv_vle32_v_i32m1(out_shift, vl);
        vint32m1_t vout_mult = __riscv_vle32_v_i32m1(out_mult, vl);
        vout_shift = __riscv_vrsub(vout_shift, 30, vl);

        vint64m2_t vout0_i64m2 = __riscv_vwmul(vch_0_out_0, vout_mult, vl);
        vint64m2_t vout1_i64m2 = __riscv_vwmul(vch_0_out_1, vout_mult, vl);
        vuint32m1_t vout_shift_unsigned = __riscv_vreinterpret_u32m1(vout_shift);
        vint32m1_t vout0 = __riscv_vnsra_wv_i32m1(vout0_i64m2, vout_shift_unsigned, vl);
        vint32m1_t vout1 = __riscv_vnsra_wv_i32m1(vout1_i64m2, vout_shift_unsigned, vl);
        vout0 = __riscv_vssra(vout0, 1, __RISCV_VXRM_RNU, vl);
        vout1 = __riscv_vssra(vout1, 1, __RISCV_VXRM_RNU, vl);

