        vint32m2_t vout1_i32m2 =  __riscv_vlmul_ext_v_i32m1_i32m2(vout1);
        vint16m1_t vout1_i16m1 = __riscv_vnsra_wx_i16m1(vout1_i32m2, 0, vl);
