            NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum
            NDS_VEC_VSETVLI(vl, col_count, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);

