                    NDS_VEC_VLB_V(NDS_VEC_V8, ptr_wt);
                    NDS_VEC_VLB_V(NDS_VEC_V10, ptr_in);
                    NDS_VEC_VWSUB_VX(NDS_VEC_V12, NDS_VEC_V10, in_offset2);
                    NDS_VEC_VSETVLI(vl, col_count2, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M4);
                    NDS_VEC_VSEXT_VF2(NDS_VEC_V16, NDS_VEC_V8);
