    out_tensor_ch = 16;
    out_tensor_dim_x = 30;
    out_tensor_dim_y = 28;
    is_bias_null = false;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "convolve_s8_scale3.bin", "convolve_s8_shift3.bin",
        "convolve_s8_golden3.bin", in_tensor_dim_x, in_tensor_dim_y,
        in_tensor_ch, in_tensor_batch, out_tensor_ch, ker_dim_x, ker_dim_y,
        pad_x, pad_y, stride_x, stride_y, out_offset, in_offset, act_min,
        act_max, out_tensor_dim_x, out_tensor_dim_y, is_bias_null);

    return retStatus;
}

