 25→int32_t riscv_nn_batch_matmul_s8_s8_s8(const int8_t * in_lhs,
 26→                                       const int8_t * in_rhs,
 27→                                       const int16_t lhs_offset,
 28→                                       const int16_t rhs_offset,
 29→                                       const int32_t * bias,
 30→                                       int8_t * dst,
 31→                                       const int16_t out_offset,
 32→                                       const int32_t out_scale,
 33→                                       const int32_t out_shift,
 34→                                       const int32_t lhs_dim_n,
 35→                                       const int32_t lhs_dim_h,
 36→                                       const int32_t lhs_dim_w,
 37→                                       const int32_t rhs_dim_n,
 38→                                       const int32_t rhs_dim_h,
 39→                                       const int32_t rhs_dim_w,
 40→                                       const int32_t rhs_dim_c,
 41→                                       const int32_t out_dim_n,
 42→                                       const int32_t out_dim_h,
 43→                                       const int32_t act_min,
 44→                                       const int32_t act_max)
 45→{
 46→#ifdef ENA_EMPTY_FUN
 47→    //empty body
 48→#elif defined(ENA_DSP_ISA) || (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ELEN64))
 49→    const int32_t output_batch = out_dim_n;
 50→    const int32_t output_height = out_dim_h;
 51→    const int32_t lhs_rows = lhs_dim_w;
 52→    const int32_t rhs_rows = rhs_dim_w;
 53→    const int32_t rhs_cols = rhs_dim_c;
 54→
 55→    const int32_t inner_lhs_diff = lhs_dim_h >= rhs_dim_h ? 0 : lhs_rows * rhs_cols;
 56→    const int32_t inner_rhs_diff = rhs_dim_h >= lhs_dim_h ? rhs_rows * rhs_cols : 0;
 57→    const int32_t outer_lhs_diff = lhs_dim_n >= rhs_dim_n
 58→        ? inner_lhs_diff
 59→        : -((lhs_rows * rhs_cols) - inner_lhs_diff) * lhs_dim_h;
 60→    const int32_t outer_rhs_diff = rhs_dim_n >= lhs_dim_n ? (rhs_rows * rhs_cols) - inner_rhs_diff
 61→                                                                          : -inner_rhs_diff * rhs_dim_h;
 62→    for (int i_out_batch = 0; i_out_batch < output_batch; i_out_batch++)
 63→    {
 64→        for (int i_out_height = 0; i_out_height < output_height; i_out_height++)
 65→        {
 66→            nn_mat_mat_mult_t_s8_s8_s8(in_lhs,
 67→                                       in_rhs,
 68→                                       lhs_offset,
 69→                                       rhs_offset,
 70→                                       bias,
 71→                                       dst,
 72→                                       out_offset,
 73→                                       out_scale,
 74→                                       out_shift,
 75→                                       lhs_rows,
 76→                                       rhs_cols,
 77→                                       rhs_rows,
 78→                                       act_min,
 79→                                       act_max);
 80→            //update pointers
 81→            in_lhs += rhs_cols * lhs_rows;
 82→            dst       += rhs_rows * lhs_rows;
 83→            in_lhs -= inner_lhs_diff;
 84→            in_rhs += inner_rhs_diff;
 85→        }
 86→        in_lhs += outer_lhs_diff;
 87→        in_rhs += outer_rhs_diff;
 88→    }
 89→#else
 90→    const int32_t output_batch = out_dim_n;
 91→    const int32_t output_height = out_dim_h;
 92→    const int32_t lhs_rows = lhs_dim_w;
 93→    const int32_t rhs_rows = rhs_dim_w;
 94→    const int32_t rhs_cols = rhs_dim_c;
 95→
 96→    const int32_t inner_lhs_diff = lhs_dim_h >= rhs_dim_h ? 0 : lhs_rows * rhs_cols;
 97→    const int32_t inner_rhs_diff = rhs_dim_h >= lhs_dim_h ? rhs_rows * rhs_cols : 0;
 98→    const int32_t outer_lhs_diff = lhs_dim_n >= rhs_dim_n
 99→        ? inner_lhs_diff
100→        : -((lhs_rows * rhs_cols) - inner_lhs_diff) * lhs_dim_h;
101→    const int32_t outer_rhs_diff = rhs_dim_n >= lhs_dim_n ? (rhs_rows * rhs_cols) - inner_rhs_diff
102→                                                                          : -inner_rhs_diff * rhs_dim_h;
103→
104→    for (int i_out_batch = 0; i_out_batch < output_batch; i_out_batch++)
105→    {
106→        for (int i_out_height = 0; i_out_height < output_height; i_out_height++)
107→        {
108→            for (int j = 0; j < lhs_rows; j++)
109→            {
110→                nn_vec_mat_mult_t_s8(in_lhs,
111→                                     in_rhs,
112→                                     bias,
113→                                     dst,
114→                                     lhs_offset,
115→                                     rhs_offset,
116→                                     out_offset,
117→                                     out_scale,
118→                                     out_shift,
119→                                     rhs_dim_c,
120→                                     rhs_rows,
121→                                     act_min,
122→                                     act_max);
123→
124→                in_lhs += rhs_cols;
125→                dst += rhs_rows;
126→            }
127→            in_lhs -= inner_lhs_diff;
128→            in_rhs += inner_rhs_diff;
129→
130→        }
131→        in_lhs += outer_lhs_diff;
132→        in_rhs += outer_rhs_diff;
133→    }
134→#endif
135→
136→    return 0;
137→}
