 24→
 25→int32_t nn_mat_mat_mult_t_s8_s8_s8(const int8_t *lhs,
 26→                                   const int8_t *rhs,
 27→                                   const int32_t lhs_offset,
 28→                                   const int32_t rhs_offset,
 29→                                   const int32_t *bias,
 30→                                   int8_t *dst,
 31→                                   const int32_t out_offset,
 32→                                   const int32_t out_scale,
 33→                                   const int32_t out_shift,
 34→                                   const int32_t lhs_rows,
 35→                                   const int32_t rhs_cols,
 36→                                   const int32_t rhs_rows,
 37→                                   const int32_t act_min,
 38→                                   const int32_t act_max)
 39→{
 40→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100)
 41→    const long out_shift2 = 30 - out_shift;
 42→    const long stride_byte = rhs_rows * sizeof(*dst);
 43→
 44→    long vl;
 45→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 46→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
 47→
 48→    int lhs_row_idx;
 49→    for (lhs_row_idx = 0; (lhs_row_idx + 2) <= lhs_rows; lhs_row_idx += 2)
 50→    {
 51→        const int8_t *rhs_ptr0 = &rhs[0];
 52→        const int8_t *rhs_ptr1 = &rhs[rhs_cols];
 53→        int8_t *pDst0 = &dst[lhs_row_idx * rhs_rows];
 54→        int8_t *pDst1 = &dst[(lhs_row_idx + 1) * rhs_rows];
 55→        const int32_t *pBias = bias;
 56→        long rest_rhs_row = rhs_rows;
 57→
 58→        while (rest_rhs_row >= 2)
 59→        {
 60→            const int8_t *lhs_ptr0 = &lhs[lhs_row_idx * rhs_cols];
 61→            const int8_t *lhs_ptr1 = &lhs[(lhs_row_idx + 1) * rhs_cols];
 62→
 63→            // init the accumulators
 64→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
 65→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
 66→            NDS_VEC_VAND_VI(NDS_VEC_V4, NDS_VEC_V4, 0);
 67→            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0);
 68→            NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0);
 69→
 70→            long rest_rhs_cols = rhs_cols;
 71→            while (rest_rhs_cols > 0)
 72→            {
 73→                NDS_VEC_VSETVLI(vl, rest_rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
 74→                NDS_VEC_VLE8_V(NDS_VEC_V17, lhs_ptr0);
 75→                NDS_VEC_VLE8_V(NDS_VEC_V19, lhs_ptr1);
 76→                NDS_VEC_VLE8_V(NDS_VEC_V21, rhs_ptr0);
 77→                NDS_VEC_VLE8_V(NDS_VEC_V23, rhs_ptr1);
 78→                NDS_VEC_VWADD_VX(NDS_VEC_V16, NDS_VEC_V17, lhs_offset);
 79→                NDS_VEC_VWADD_VX(NDS_VEC_V18, NDS_VEC_V19, lhs_offset);
 80→                NDS_VEC_VWADD_VX(NDS_VEC_V20, NDS_VEC_V21, rhs_offset);
 81→                NDS_VEC_VWADD_VX(NDS_VEC_V22, NDS_VEC_V23, rhs_offset);
 82→
 83→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
 84→                NDS_VEC_VWMACC_VV(NDS_VEC_V0, NDS_VEC_V16, NDS_VEC_V20);
 85→                NDS_VEC_VWMACC_VV(NDS_VEC_V4, NDS_VEC_V16, NDS_VEC_V22);
 86→                NDS_VEC_VWMACC_VV(NDS_VEC_V8, NDS_VEC_V18, NDS_VEC_V20);
 87→                NDS_VEC_VWMACC_VV(NDS_VEC_V12, NDS_VEC_V18, NDS_VEC_V22);
 88→
 89→                lhs_ptr0 += vl;
 90→                lhs_ptr1 += vl;
 91→                rhs_ptr0 += vl;
 92→                rhs_ptr1 += vl;
 93→                rest_rhs_cols -= vl;
 94→            }
 95→
 96→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);    //note the avl here
 97→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
 98→            NDS_VEC_VREDSUM_VS(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V31);
 99→            NDS_VEC_VREDSUM_VS(NDS_VEC_V1, NDS_VEC_V8, NDS_VEC_V31);
100→            NDS_VEC_VREDSUM_VS(NDS_VEC_V3, NDS_VEC_V12, NDS_VEC_V31);

 50→                                                     const int32_t act_min,
 51→                                                     const int32_t act_max,
 52→                                                     const uint16_t out_tensor_dim_x,
 53→                                                     int16_t * in_tmp_buf)
 54→{
 55→    int status = 0;
 56→#ifdef ENA_EMPTY_FUN
 57→    //empty body
 58→#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
 59→    const int32_t rhs_cols = ker_dim_x * in_tensor_ch;
 60→    long maxvl_per_loop;
 61→    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 62→
 63→    //--- calculate the buffer address ---
 64→    const long align_byte = sizeof(long);
 65→    // buffer-1
 66→    int8_t *two_column_buf = (int8_t*)in_tmp_buf;
 67→    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);          // align the starting addresss
 68→    // buffer-2
 69→    long two_column_buf_size = 2 * in_tensor_ch * ker_dim_x * sizeof(*in_tensor);
 70→    int32_t *contri_buf = (int32_t *)(two_column_buf + two_column_buf_size);
 71→    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);    // align the starting addresss
 72→
 73→    // calculate the extra contribution
 74→    const int8_t *pWt = ker_weight;
 75→    long vl;
 76→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 77→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
 78→
 79→    if (bias != NULL)
 80→    {
 81→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
 82→        {
 83→            long rhs_cols2 = rhs_cols;
 84→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 85→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
 86→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 87→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot
 88→
 89→            while (rhs_cols2 >= maxvl_per_loop)
 90→            {
 91→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 92→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
 93→                pWt += vl;
 94→                rhs_cols2 -= vl;
 95→
 96→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 97→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 98→            }
 99→
100→            //clean one of the dot product source
101→            long tmp_vl = rhs_cols2 + 3;
102→            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
103→            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
104→            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
105→            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);
106→
107→            while (rhs_cols2 > 0)
108→            {
109→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
110→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
111→                pWt += vl;
112→                rhs_cols2 -= vl;
113→
114→                vl = (vl + 3) >> 2;
115→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
116→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
117→            }
118→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
119→            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
120→
121→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
122→            const int32_t *pBias = &bias[cur_out_ch];
123→            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
124→            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
125→            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias
126→
127→            int32_t *pContri_buf = &contri_buf[cur_out_ch];
128→            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
129→        }
130→    }
131→    else
132→    {
133→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
134→        {
135→            long rhs_cols2 = rhs_cols;
136→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
137→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
138→            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
139→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);    // const one for vd4dot
140→
141→            while (rhs_cols2 >= maxvl_per_loop)
142→            {
143→                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
144→                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
145→                pWt += vl;
146→                rhs_cols2 -= vl;
147→
148→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
149→                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
150→            }
151→
152→            //clean one of the dot product source
153→            long tmp_vl = rhs_cols2 + 3;
154→            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
