    //empty body
#elif defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64)
    const int32_t rhs_cols = ker_dim_x * in_tensor_ch;
    long maxvl_per_loop;
    NDS_VEC_VSETVLI(maxvl_per_loop, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);

    //--- calculate the buffer address ---
    const long align_byte = sizeof(long);
    // buffer-1
    int8_t *two_column_buf = (int8_t*)in_tmp_buf;
    two_column_buf = (int8_t*)nn_align((unsigned long)two_column_buf, align_byte);          // align the starting addresss
    // buffer-2
    long two_column_buf_size = 2 * in_tensor_ch * ker_dim_x * sizeof(*in_tensor);
    int32_t *contri_buf = (int32_t *)(two_column_buf + two_column_buf_size);
    contri_buf = (int32_t*)nn_align((unsigned long)contri_buf, align_byte);    // align the starting addresss

    // calculate the extra contribution
    const int8_t *pWt = ker_weight;
    long vl;
    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum

    if (bias != NULL)
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long rhs_cols2 = rhs_cols;
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot

            while (rhs_cols2 >= maxvl_per_loop)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = rhs_cols2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (rhs_cols2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            const int32_t *pBias = &bias[cur_out_ch];
            NDS_VEC_VLE32_V(NDS_VEC_V8, pBias);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);     // add input_offset contribution back
            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V8);    // add bias

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }
    else
    {
        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
        {
            long rhs_cols2 = rhs_cols;
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);    // const one for vd4dot

            while (rhs_cols2 >= maxvl_per_loop)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }

            //clean one of the dot product source
            long tmp_vl = rhs_cols2 + 3;
            NDS_VEC_VSETVLI(vl, tmp_vl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);
            NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VADD_VI(NDS_VEC_V16, NDS_VEC_V16, 1);

            while (rhs_cols2 > 0)
            {
                NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VLE8_V(NDS_VEC_V8, pWt);
                pWt += vl;
                rhs_cols2 -= vl;

                vl = (vl + 3) >> 2;
                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
            }
            NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

            // add input_offset contribution back
            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, in_offset);

            int32_t *pContri_buf = &contri_buf[cur_out_ch];
            NDS_VEC_VSE32_V(NDS_VEC_V0, pContri_buf);
        }
    }


    int8_t *out = out_tensor;
    for (int32_t cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
    {
        // This part implements the im2col function
        int8_t *two_column_buf = (int8_t *)in_tmp_buf;
        for (int32_t cur_out_x = 0; cur_out_x < out_tensor_dim_x; cur_out_x++)
        {
            for (int32_t cur_ker_x = cur_out_x * stride_x - pad_x; cur_ker_x < cur_out_x * stride_x - pad_x + ker_dim_x; cur_ker_x++)
            {
                if (cur_ker_x < 0 || cur_ker_x >= in_tensor_dim_x)
                {
                    nn_set_val_s8(two_column_buf, -in_offset, in_tensor_ch);
                }
                else
                {
                    nn_dup_s8(in_tensor + cur_ker_x * in_tensor_ch, two_column_buf, in_tensor_ch);
                }
                two_column_buf += in_tensor_ch;
            }

            // Computation is filed for every 2 columns
            if (two_column_buf == (int8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x)
            {
                out = nn_mat_mult_kernel_s8_offset_v2(ker_weight,
                                                      (int8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      out_shift,
                                                      out_scale,
                                                      in_offset,
                                                      out_offset,
                                                      act_min,
                                                      act_max,
                                                      in_tensor_ch * ker_dim_x,
                                                      contri_buf,
                                                      out);

                // counter reset
                two_column_buf = (int8_t *)in_tmp_buf;
            }
        }

        // left-over because odd number of output pixels
        if (two_column_buf != (int8_t *)in_tmp_buf)
        {
            const int8_t *pWt = ker_weight;
            for (int i = 0; i < out_tensor_ch; i++)
            {
                // setup the pointers
                const int8_t *pIn = (int8_t *)in_tmp_buf;

                //load the extra contribution
                long vl;
                int32_t *pContri_buf = &contri_buf[i];
                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
                NDS_VEC_VLE32_V(NDS_VEC_V31, pContri_buf);

                //init the accumulator
                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);

                long rhs_cols2 = rhs_cols;
                while (rhs_cols2 >= maxvl_per_loop)
                {
                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
                    pIn += vl;
                    pWt += vl;
                    rhs_cols2 -= vl;

                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
                }

                //extra process for the case of elements to be dot producted is not a mutiple of 4
                if (rhs_cols2 > 0)
                {
                    //clean one of the dot product source
                    long tmp_avl;
                    tmp_avl = rhs_cols2 + 3;
                    NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0);

                    NDS_VEC_VSETVLI(vl, rhs_cols2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VLE8_V(NDS_VEC_V8, pIn);
                    NDS_VEC_VLE8_V(NDS_VEC_V16, pWt);
                        // pIn += vl;
                    pWt += vl;

                    vl = (vl + 3) >> 2;
                    NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
                    NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
                }

                NDS_VEC_VSETVLI(vl, rhs_cols, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);    //note the avl here
                NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);

                //move vr results to gpr
                int32_t sum;
                NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);

                sum = nn_requantize(sum, out_scale[i], out_shift[i]);
                sum += out_offset;
                sum = MAX(sum, act_min);
                sum = MIN(sum, act_max);
                *out = (int8_t)sum;
                out++;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_ch);
    }
#elif defined(ENA_DSP_ISA_64)
    int32_t i_batch, i_out_x, i_ker_x;
    int8_t *out = out_tensor;

    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        /* This part implements the im2col function */
        int8_t *two_column_buf = (int8_t *)in_tmp_buf;
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
            {
                if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                {
                    nn_set_val_s8(two_column_buf, -in_offset, in_tensor_ch);
                }
                else
                {
                    nn_dup_s8(in_tensor + i_ker_x * in_tensor_ch, two_column_buf, in_tensor_ch);
                }
                two_column_buf += in_tensor_ch;
            }

            /* Computation is filed for every 2 columns */
            if (two_column_buf == (int8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x)
            {
                out = nn_mat_mult_kernel_s8_offset(ker_weight,
                                                   (int8_t *)in_tmp_buf,
                                                   out_tensor_ch,
                                                   out_shift,
                                                   out_scale,
                                                   in_offset,
                                                   out_offset,
                                                   act_min,
                                                   act_max,
                                                   in_tensor_ch * ker_dim_x,
                                                   bias,
                                                   out);

                /* counter reset */
                two_column_buf = (int8_t *)in_tmp_buf;
            }
        }

        /* left-over because odd number of output pixels */
        if (two_column_buf != (int8_t *)in_tmp_buf)
        {
            const int8_t *ker_a = ker_weight;
            int i;

            for (i = 0; i < out_tensor_ch; i++)
            {
                /* Load the accumulator with bias first */
                q63_t sum = 0;
                if (bias)
                {
                    sum = (uint32_t)bias[i];
                }

                /* Point to the beginning of the im2col buffer where the input is available as a rearranged column */
                const int8_t *ip_as_col = (int8_t *)in_tmp_buf;

                /* 4 multiply and accumulates are done in one loop. */
                uint16_t col_count = (in_tensor_ch * ker_dim_x) >> 3;

                q63_t sum_ker_a = 0;
                q63_t scale = 0x0101010101010101;

                while (col_count)
                {
                    q63_t  ker_a1 = *__SIMD64(ker_a)++;
                    q63_t ip_b1 = *__SIMD64(ip_as_col)++;

                    sum = NDS_DSP_SMAQA(sum, ker_a1, ip_b1);

                    //here we just want to accumulate the 4 int8_t a values into sum_ker_a
                    sum_ker_a = NDS_DSP_SMAQA(sum_ker_a, ker_a1, scale);

                    col_count--;
                }

                //sum up high and low part 32-bits SIMD results
                sum = PADD_S32(sum);
                sum_ker_a = PADD_S32(sum_ker_a);

                /* Handle left over mac */
                col_count = in_tensor_ch * ker_dim_x & 0x7;
                while (col_count)
                {
                    int8_t ker_a1 = *ker_a++;
                    int8_t ip_b1 = *ip_as_col++;
                    sum += ker_a1 * ip_b1;
                    sum_ker_a += ker_a1;
                    col_count--;
                }

                //add offset back
                sum += in_offset * sum_ker_a;

                sum = nn_requantize(sum, out_scale[i], out_shift[i]);
                sum += out_offset;
                sum = MAX(sum, act_min);
                sum = MIN(sum, act_max);
                *out++ = (int8_t)sum;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_ch);
    }
#elif defined(ENA_DSP_ISA_V5)
    int32_t i_batch, i_out_x, i_ker_x;
    int8_t *out = out_tensor;

    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        /* This part implements the im2col function */
        int8_t *two_column_buf = (int8_t *)in_tmp_buf;
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
            {
                if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                {
                    nn_set_val_s8(two_column_buf, -in_offset, in_tensor_ch);
                }
                else
                {
                    nn_dup_s8(in_tensor + i_ker_x * in_tensor_ch, two_column_buf, in_tensor_ch);
                }
                two_column_buf += in_tensor_ch;
            }

            /* Computation is filed for every 2 columns */
            if (two_column_buf == (int8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x)
            {
                out = nn_mat_mult_kernel_s8_offset(ker_weight,
                                                   (int8_t *)in_tmp_buf,
                                                   out_tensor_ch,
                                                   out_shift,
                                                   out_scale,
                                                   in_offset,
                                                   out_offset,
                                                   act_min,
                                                   act_max,
                                                   in_tensor_ch * ker_dim_x,
                                                   bias,
                                                   out);

                /* counter reset */
                two_column_buf = (int8_t *)in_tmp_buf;
            }
        }

        /* left-over because odd number of output pixels */
        if (two_column_buf != (int8_t *)in_tmp_buf)
        {
            const int8_t *ker_a = ker_weight;
            int i;

            for (i = 0; i < out_tensor_ch; i++)
            {
                /* Load the accumulator with bias first */
                int32_t sum = 0;
                if (bias)
                {
                    sum = bias[i];
                }

                /* Point to the beginning of the im2col buffer where the input is available as a rearranged column */
                const int8_t *ip_as_col = (int8_t *)in_tmp_buf;

                /* 4 multiply and accumulates are done in one loop. */
                uint16_t col_count = (in_tensor_ch * ker_dim_x) >> 2;

                int32_t sum_ker_a = 0;
                int32_t scale = 0x01010101;

                while (col_count)
                {
                    int32_t ker_a_val;
                    int32_t ip_b;

                    ker_a_val = *__SIMD32(ker_a)++;
                    ip_b = *__SIMD32(ip_as_col)++;

                    sum = NDS_DSP_SMAQA(sum, ker_a_val, ip_b);
                    sum_ker_a = NDS_DSP_SMAQA(sum_ker_a, ker_a_val, scale);

                    col_count--;
                }

                /* Handle left over mac */
                col_count = (in_tensor_ch * ker_dim_x) & 0x3;
                while (col_count)
                {
                    int8_t ker_a1 = *ker_a++;
                    int8_t ip_b1 = *ip_as_col++;
                    sum += ker_a1 * ip_b1;
                    sum_ker_a += ker_a1;
                    col_count--;
                }

                //add offset back
                sum += in_offset * sum_ker_a;

                sum = nn_requantize(sum, out_scale[i], out_shift[i]);
                sum += out_offset;
                sum = MAX(sum, act_min);
                sum = MIN(sum, act_max);
                *out++ = (int8_t)sum;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_ch);
    }
#else
    (void)in_tmp_buf;
    int32_t i_batch, i_out_ch, i_out_x, i_input_ch, i_ker_x;
    int32_t conv_out;

    for (i_batch = 0; i_batch < in_tensor_batch; i_batch++)
    {
        for (i_out_ch = 0; i_out_ch < out_tensor_ch; i_out_ch++)
        {
            for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
            {
                conv_out = 0;
                if (bias)
                {
                    conv_out = bias[i_out_ch];
                }

                const int32_t base_idx_y = 0;
                const int32_t base_idx_x = stride_x * i_out_x - pad_x;

                const int32_t ker_x_start = MAX(0, -base_idx_x);
                const int32_t ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);

                for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                {
                    const int32_t in_row = base_idx_y;
                    const int32_t in_col = base_idx_x + i_ker_x;
                    for (i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
                    {
                        conv_out += (in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + i_input_ch] + in_offset) *
                                    ker_weight[i_out_ch * in_tensor_ch * ker_dim_x + (+ i_ker_x) * in_tensor_ch + i_input_ch];
                    }
                }

                conv_out = nn_requantize(conv_out, out_scale[i_out_ch], out_shift[i_out_ch]);
                conv_out += out_offset;
                conv_out = MAX(conv_out, act_min);
                conv_out = MIN(conv_out, act_max);
                out_tensor[i_out_ch + (i_out_x) * out_tensor_ch] = conv_out;
            }
        }

        in_tensor += (in_tensor_dim_x * in_tensor_ch);
        out_tensor += (out_tensor_dim_x * out_tensor_ch);
    }
#endif

    /* Return to application */
    return status;
}

int32_t riscv_nn_conv_1xn_HWC_s8_s8_s8_asym_bias_any_get_buffer_size(const uint16_t in_tensor_dim_x,
                                                                     const uint16_t in_tensor_ch,
                                                                     const uint16_t out_tensor_ch,
                                                                     const uint16_t ker_dim_x,
                                                                     const uint16_t pad_x,
                                                                     const uint16_t stride_x,
                                                                     const uint16_t out_tensor_dim_x)
{
#if defined(ENA_DSP_ISA_V5) || (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_ELEN64))
    (void)in_tensor_dim_x;
    (void)pad_x;
    (void)stride_x;
    (void)out_tensor_dim_x;
    const long align_byte = sizeof(long);

    // two col buffer
    int32_t buf_size = 2 * in_tensor_ch * ker_dim_x * sizeof(int8_t);
    buf_size += align_byte - 1;     //extra size for aligning

    // buffer for extra contribution
    buf_size += out_tensor_ch * sizeof(int32_t);
    buf_size += align_byte - 1;     //extra size for aligning

    return buf_size;
#else
    (void)in_tensor_dim_x;
    (void)in_tensor_ch;
    (void)out_tensor_ch;
    (void)ker_dim_x;
    (void)pad_x;
    (void)stride_x;
    (void)out_tensor_dim_x;
    return 0;
#endif
}

