int main (void)
{
    enable_fs_and_vs();
    uint16_t in_tensor_dim_x, in_tensor_ch, in_tensor_batch, out_tensor_ch,
    ker_dim_x,  pad_x,  stride_x, out_tensor_dim_x;
    int32_t out_offset, in_offset, act_min, act_max;
    uint32_t retStatus=NDS_SUCCESS;
    bool is_bias_null;

    act_min = 0xffffff81;
    act_max = 0x0000007e;

#if !ENA_MEASURE_PERF
    //test-1 (assume pad_left=1 and pad_right=2)
    ker_dim_x = 3;
    pad_x = 1;
    stride_x = 1;
    out_offset = 5;
    in_offset = 3;
    in_tensor_batch = 3;
    in_tensor_dim_x = 10;
    in_tensor_ch = 684;
    out_tensor_ch = 5;
    out_tensor_dim_x = 11;
    is_bias_null = false;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_scale.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_shift.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_golden.bin", in_tensor_dim_x,
        in_tensor_ch, in_tensor_batch, out_tensor_ch, ker_dim_x, pad_x,
        stride_x, out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
        is_bias_null);

    //test-2 (assume pad_left=1 and pad_right=2)
    ker_dim_x = 3;
    pad_x = 1;
    stride_x = 2;
    out_offset = 5;
    in_offset = 3;
    in_tensor_batch = 2;
    in_tensor_dim_x = 64;
    in_tensor_ch = 684;
    out_tensor_ch = 31;
    out_tensor_dim_x = 33;
    is_bias_null = true;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_scale2.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_shift2.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_golden2.bin", in_tensor_dim_x,
        in_tensor_ch, in_tensor_batch, out_tensor_ch, ker_dim_x, pad_x,
        stride_x, out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
        is_bias_null);
#endif

    //test-3
    ker_dim_x = 3;
    pad_x = 0;
    stride_x = 1;
    out_offset = 5;
    in_offset = 3;
    in_tensor_batch = 1;
    in_tensor_dim_x = 32;
    in_tensor_ch = 512;
    out_tensor_ch = 32;
    out_tensor_dim_x = 16;
    is_bias_null = false;
    retStatus |= test("8b_in1.bin", "8b_in2.bin", "32b_in1.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_scale3.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_shift3.bin",
        "conv_1xn_HWC_s8_s8_s8_asym_bias_any_golden3.bin", in_tensor_dim_x,
        in_tensor_ch, in_tensor_batch, out_tensor_ch, ker_dim_x, pad_x,
        stride_x, out_offset, in_offset, act_min, act_max, out_tensor_dim_x,
        is_bias_null);

    return retStatus;
}
